code.C++:
# cook your dish here
t=int(input())
for i in range(t):
    x1,x2,y1,y2=map(int,input().split())
    if (y1/x1)<(y2/x2):
        print(-1)
    elif (y1/x1)==(y2/x2):
        print(0)
    else:
        print(1)

